def test_validate_rejects_null_required_value():
    # pass-7: a key present but null sails through the presence check then TypeErrors
    # downstream — reject it at load.
    cfg = _valid_cfg()
    cfg["checkpointing"]["database"] = None
    with pytest.raises(config.ConfigError, match="is null"):
        config._validate_config(cfg, "test")


@pytest.mark.parametrize("backend", ["redis", "sqlite", "", "Postgres"])
def test_validate_rejects_unknown_checkpointing_backend(backend):
    cfg = _valid_cfg()
    cfg["checkpointing"]["backend"] = backend
    with pytest.raises(config.ConfigError, match="backend"):
        config._validate_config(cfg, "test")


@pytest.mark.parametrize("backend", ["memory", "postgres"])
